const item = $input.first();
const binary = item.binary || {};
const out = [];

for (const key of Object.keys(binary)) {
  const meta = binary[key];
  out.push({
    json: {
      file_name: meta.fileName || '',
      mime_type: meta.mimeType || '',
      source_subject: item.json.subject || '',
      source_from: item.json.from || '',
    },
    binary: { data: meta },   // normalize every attachment to the key "data"
  });
}

return out;

const d = $input.first().json.data;

// Extractor returns null for missing fields — but also catch the string "null" and empties
const isMissing = (v) =>
  v === null || v === undefined || String(v).trim().toLowerCase() === 'null' || String(v).trim() === '';

// Arrays sometimes come back JSON-encoded or comma-joined
const toArray = (v) => {
  if (isMissing(v)) return [];
  if (Array.isArray(v)) return v;
  const s = String(v).trim();
  if (s.startsWith('[')) {
    try { return JSON.parse(s); } catch (e) { /* fall through */ }
  }
  return s.split(',').map(x => x.trim()).filter(Boolean);
};

const clean = (v, fallback = '') => isMissing(v) ? fallback : String(v).trim();

// Constrain free-text enums to known values
const normEnum = (v, allowed, fallback) => {
  const s = clean(v).toLowerCase();
  return allowed.includes(s) ? s : fallback;
};

const strengths = toArray(d.claimed_strengths);
const weaknesses = toArray(d.claimed_weaknesses);

return [{
  json: {
    referee_name:          clean(d.referee_name, 'Unknown'),
    referee_title_company: clean(d.referee_title_company),
    candidate_name:        clean(d.candidate_name, 'Unknown'),
    relationship_type:     clean(d.relationship_type).toLowerCase(),
    duration_known:        clean(d.duration_known),
    claimed_strengths:     strengths,
    claimed_weaknesses:    weaknesses,
    strengths_text:        strengths.join('; '),
    weaknesses_text:       weaknesses.length ? weaknesses.join('; ') : '— none stated —',
    would_rehire:          normEnum(d.would_rehire, ['yes', 'no', 'unstated'], 'unstated'),
    tone:                  normEnum(d.tone, ['positive', 'neutral', 'hedged'], 'neutral'),
    notable_quote:         clean(d.notable_quote),
  }
}];

const r = $input.first().json;

let score = 50; // neutral baseline

// Tone (LLM's first-pass read, used as input, not as final grade)
if (r.tone === 'positive') score += 25;
if (r.tone === 'hedged')   score -= 25;

// Would-rehire is the single strongest signal in reference checking
if (r.would_rehire === 'yes') score += 20;
if (r.would_rehire === 'no')  score -= 35;

// Substance: a real reference names specifics
score += Math.min(r.claimed_strengths.length * 3, 12);

// A reference with zero stated weaknesses is often a polite non-endorsement
if (r.claimed_weaknesses.length === 0 && r.would_rehire !== 'yes') score -= 8;

score = Math.max(0, Math.min(100, score));

// Tier for routing / colour-coding the sheet
let tier = 'mid';
if (score >= 75) tier = 'high';
if (score < 45)  tier = 'low';

return [{ json: { ...r, sentiment_score: score, sentiment_tier: tier } }];
